import {createRoot} from 'react-dom/client';
import {ArrowRight, BarChart3, CalendarDays, Camera, Check, CheckCircle2, ChevronRight, Clock3, Download, IdCard, LayoutDashboard, LogOut, Medal, Menu, Plus, Printer, QrCode, Radio, Search, Settings, Sparkles, Trophy, UserCheck, Users, X, Zap} from 'lucide-react';
